from typing import Dict, List, Optional


class TrieNode:
    """A single node in the trie, holding child nodes and an end-of-word flag."""

    def __init__(self) -> None:
        """Initialize a node with no children and not marking a word's end."""
        self.children: Dict[str, "TrieNode"] = {}
        self.is_end_of_word: bool = False


class Trie:
    """A prefix tree supporting insertion, exact search, prefix checks, and autocomplete."""

    def __init__(self) -> None:
        """Initialize an empty trie with a root node."""
        self.root: TrieNode = TrieNode()

    def insert(self, word: str) -> None:
        """Insert a word into the trie. Inserting an empty string is a no-op."""
        if not word:
            return
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def _find_node(self, prefix: str) -> Optional[TrieNode]:
        """Return the node at the end of the given prefix path, or None if absent."""
        node = self.root
        for char in prefix:
            if char not in node.children:
                return None
            node = node.children[char]
        return node

    def search(self, word: str) -> bool:
        """Return True only if the exact complete word exists in the trie."""
        if not word:
            return False
        node = self._find_node(word)
        return node is not None and node.is_end_of_word

    def starts_with(self, prefix: str) -> bool:
        """Return True if any inserted word starts with the given prefix."""
        if not prefix:
            # Every word starts with the empty prefix (if any word exists).
            return bool(self.root.children)
        return self._find_node(prefix) is not None

    def autocomplete(self, prefix: str, max_results: int = 5) -> List[str]:
        """Return up to max_results words starting with prefix, sorted alphabetically.

        Uses DFS from the prefix node to collect completions without scanning all words.
        """
        if max_results <= 0:
            return []

        start = self._find_node(prefix)
        if start is None:
            return []

        results: List[str] = []

        def dfs(node: TrieNode, path: str) -> None:
            if len(results) >= max_results:
                return
            if node.is_end_of_word:
                results.append(path)
                if len(results) >= max_results:
                    return
            # Visiting children in sorted order yields alphabetical results.
            for char in sorted(node.children):
                dfs(node.children[char], path + char)
                if len(results) >= max_results:
                    return

        dfs(start, prefix)
        return results


if __name__ == "__main__":
    trie = Trie()
    for w in ["apple", "app", "application", "apt", "bat", "batch", "bath"]:
        trie.insert(w)

    print('search("app")        =>', trie.search("app"))
    print('search("ap")         =>', trie.search("ap"))
    print('starts_with("ap")    =>', trie.starts_with("ap"))
    print('autocomplete("app")  =>', trie.autocomplete("app"))
    print('autocomplete("bat")  =>', trie.autocomplete("bat"))
    print('autocomplete("xyz")  =>', trie.autocomplete("xyz"))
```

**Output:**

```
search("app")        => True
search("ap")         => False
starts_with("ap")    => True
autocomplete("app")  => ['app', 'apple', 'application']
autocomplete("bat")  => ['bat', 'batch', 'bath']
autocomplete("xyz")  => []
```

**Notes on the design and edge cases:**

- **DFS efficiency**: `autocomplete` first walks to the prefix node in O(len(prefix)), then DFS explores only the subtree under that prefix — never the whole trie. Sorting children at each node guarantees alphabetical order, and the early `len(results) >= max_results` checks stop the descent as soon as the quota is filled.
- **Empty string**: `insert("")` is a no-op; `search("")` returns `False` (no real word). `autocomplete("")` would return the alphabetically-first words across the whole trie.
- **Prefix longer than any word**: `_find_node` returns `None` partway through, so `starts_with` and `autocomplete` correctly report nothing.
- **Single-character words**: handled naturally — e.g. inserting `"a"` sets `is_end_of_word` on the root's `"a"` child.

The code is self-contained, uses only builtins, and is runnable as-is (`python trie.py`).

